import{_ as t,o as i,c as a,a2 as n}from"./chunks/framework.ufzXw1qY.js";const b=JSON.parse('{"title":"Ultimate CI/CD via n8n & sin-github-action","description":"Mandatory zero-billing delivery doctrine using OCI, n8n, and controlled automation instead of standard GitHub-hosted runners.","frontmatter":{"title":"Ultimate CI/CD via n8n & sin-github-action","description":"Mandatory zero-billing delivery doctrine using OCI, n8n, and controlled automation instead of standard GitHub-hosted runners."},"headers":[],"relativePath":"best-practices/ci-cd-n8n.md","filePath":"best-practices/ci-cd-n8n.md"}'),r={name:"best-practices/ci-cd-n8n.md"};function o(l,e,s,d,h,c){return i(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="ultimate-ci-cd-via-n8n-sin-github-action" tabindex="-1">Ultimate CI/CD via n8n &amp; sin-github-action <a class="header-anchor" href="#ultimate-ci-cd-via-n8n-sin-github-action" aria-label="Permalink to &quot;Ultimate CI/CD via n8n &amp; sin-github-action&quot;">​</a></h1><blockquote><p><strong>RULE:</strong> Standard GitHub-hosted Actions runners are banned for core OpenSIN delivery paths when the OCI+n8n zero-billing route exists.</p></blockquote><hr><h2 id="_1-why-this-exists" tabindex="-1">1. Why This Exists <a class="header-anchor" href="#_1-why-this-exists" aria-label="Permalink to &quot;1. Why This Exists&quot;">​</a></h2><p>The fleet must keep delivery:</p><ul><li>cheap</li><li>observable</li><li>reproducible</li><li>controllable</li><li>integrated with our issue/dispatch model</li></ul><p>n8n on OCI gives us exactly that.</p><hr><h2 id="_2-canonical-delivery-path" tabindex="-1">2. Canonical Delivery Path <a class="header-anchor" href="#_2-canonical-delivery-path" aria-label="Permalink to &quot;2. Canonical Delivery Path&quot;">​</a></h2><p>GitHub event → n8n workflow on OCI → controlled runner / scripts → artifacts / deploy / notifications</p><h3 id="why" tabindex="-1">Why <a class="header-anchor" href="#why" aria-label="Permalink to &quot;Why&quot;">​</a></h3><p>This keeps delivery inside our own automation backbone instead of outsourcing critical orchestration to an opaque hosted runner model.</p><hr><h2 id="_3-what-belongs-in-ci-cd" tabindex="-1">3. What Belongs in CI/CD <a class="header-anchor" href="#_3-what-belongs-in-ci-cd" aria-label="Permalink to &quot;3. What Belongs in CI/CD&quot;">​</a></h2><ul><li>lint/build/test gates</li><li>deployment packaging</li><li>branch / PR checks</li><li>release notes / notifications</li><li>environment validation</li></ul><hr><h2 id="_4-what-must-be-avoided" tabindex="-1">4. What Must Be Avoided <a class="header-anchor" href="#_4-what-must-be-avoided" aria-label="Permalink to &quot;4. What Must Be Avoided&quot;">​</a></h2><ul><li>hidden runner behavior</li><li>expensive unnecessary jobs</li><li>duplicate workflows in GitHub and n8n doing the same thing</li><li>deployment scripts that cannot be rerun safely</li></ul><hr><h2 id="_5-required-properties" tabindex="-1">5. Required Properties <a class="header-anchor" href="#_5-required-properties" aria-label="Permalink to &quot;5. Required Properties&quot;">​</a></h2><p>Every CI/CD flow should be:</p><ul><li>idempotent where possible</li><li>visible in logs</li><li>linked to issue/PR state</li><li>fail-closed on missing secrets or invalid config</li><li>able to notify operators on failure</li></ul><hr><h2 id="_6-final-rule" tabindex="-1">6. Final Rule <a class="header-anchor" href="#_6-final-rule" aria-label="Permalink to &quot;6. Final Rule&quot;">​</a></h2><p><strong>CI/CD is not “whatever makes the green checkmark appear.”</strong> It is controlled, observable delivery with minimal cost and maximal evidence.</p><hr><p><em>Last updated:</em> 2026-04-10<br><em>Status:</em> <strong>ACTIVE &amp; MANDATORY</strong><br><em>Maintainer:</em> sin-zeus</p><hr><h2 id="relevante-mandate" tabindex="-1">Relevante Mandate <a class="header-anchor" href="#relevante-mandate" aria-label="Permalink to &quot;Relevante Mandate&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mandat</th><th>Priority</th><th>Regel</th></tr></thead><tbody><tr><td><strong>n8n OSS Only</strong></td><td>0.0</td><td>KEINE n8n Premium Features</td></tr><tr><td><strong>Self-Hosted CI/CD</strong></td><td>0.0</td><td>OCI VM — KEINE GitHub Actions Runner</td></tr><tr><td><strong>Bun-Only</strong></td><td>-1.5</td><td><code>bun install</code> / <code>bun run</code></td></tr></tbody></table>',30)])])}const p=t(r,[["render",o]]);export{b as __pageData,p as default};
